// // This module selects between two 8-bit inputs based on the select signal. When select is HIGH, out reflects in0; when select is LOW, out reflects in1.
module top_module(
    input [7:0] in0,
    input [7:0] in1,
    input select,
    output [7:0] out
    );assign out = select ? in1 : in0;
endmodule
